        print(f"  'conversation' type: {type(c0['conversation'])}")
        if isinstance(c0['conversation'], dict):
            print(f"  'conversation' keys: {list(c0['conversation'].keys())}")
    if 'responses' in c0:
        print(f"  'responses' type: {type(c0['responses'])}")
        if isinstance(c0['responses'], list) and len(c0['responses']) > 0:
            r0 = c0['responses'][0]
            print(f"  First response type: {type(r0)}")
            if isinstance(r0, dict):
                print(f"  First response keys: {list(r0.keys())[:20]}")
                # Check for message content
                for k in r0:
                    if isinstance(r0[k], str) and len(r0[k]) > 50:
                        print(f"  Key '{k}' sample: {r0[k][:200]}")

# Now search matching convs
for conv in conversations:
    conv_str = json.dumps(conv)
    if not PATTERN.search(conv_str):
        continue

    # Get conversation user query
    c = conv.get('conversation', {})
