                for key in resp:
                    if isinstance(resp[key], dict):
                        sub_str = json.dumps(resp[key])
                        if PATTERN.search(sub_str):
                            for subkey in resp[key]:
                                if isinstance(resp[key][subkey], str) and PATTERN.search(resp[key][subkey]):
